// pages/index.js – /
function Home() {
  return <h1>Ana Səhifə</h1>;
}

export default Home;

// pages/about.js – /about
function About() {
  return <h1>Haqqımızda</h1>;
}

export default About;

// pages/blog/[id].js – /blog/1, /blog/2 (dynamic)
function BlogPost({ params }) {
  return <h1>Blog ID: {params.id}</h1>;
}

export default BlogPost;

console.log('Pages Router nümunəsi');

// app/page.js – /
export default function Home() {
  return <h1>Ana Səhifə (App Router)</h1>;
}

// app/about/page.js – /about
export default function About() {
  return <h1>Haqqımızda</h1>;
}

// app/blog/[id]/page.js – /blog/1 (dynamic)
export default function BlogPost({ params }) {
  return <h1>Blog ID: {params.id}</h1>;
}

console.log('App Router nümunəsi');

// app/layout.js (root layout)
export default function RootLayout({ children }) {
  return (
    <html>
      <body>{children}</body>
    </html>
  );
}

// app/dashboard/layout.js
export default function DashboardLayout({ children }) {
  return (
    <div>
      <nav>Dashboard Nav</nav>
      {children}
    </div>
  );
}

console.log('Nested layout nümunəsi');

import Link from 'next/link';

function Navigation() {
  return (
    <nav>
      <Link href="/">Ana</Link>
      <Link href="/about">Haqqımızda</Link>
    </nav>
  );
}

console.log('Link komponenti nümunəsi');

